// Tier-1 → Tier-2 checksum migration for reclassified templates.
//
// When forge reclassifies a template from Tier-1 (regenerated every
// run) to Tier-2 (scaffold-once, user-owned), projects generated by an
// older forge still carry tier=1 (or the legacy unset tier=0) for that
// path in `.forge/checksums.json`. The stale tier has three bad
// consequences:
//
//   - The Tier-1 stomp guard keeps drift-erroring on a file the user is
//     now SUPPOSED to own and edit (Dockerfile, Taskfile.yml, …).
//   - Users silence the guard by disowning the file — and a disown on
//     a starter-class file is noise in `forge audit`'s disowned report
//     forever after (the file was never really forge-owned to begin
//     with).
//
// This step is the inverse of generate_skills.go's Tier-2→Tier-1 skill
// migration: for every tracked entry whose path the current template
// registry declares Tier-2 (generator.Tier2ManagedPaths), flip the
// entry to tier=2 and clear the forked flag. The on-disk file is left
// untouched — it is simply user-owned now. The recorded hash/history
// are also left untouched: they still describe the last render forge
// produced, which is exactly what `forge upgrade`'s
// MatchesAnyKnownRender check needs to distinguish "user customized
// this starter" (skip) from "still the pristine scaffold" (safe to
// auto-update).
//
// Ordering: must run AFTER "load checksums" and BEFORE the Tier-1
// stomp guard, so a hand-edited reclassified file stops blocking the
// very generate run that performs the migration. The pipeline runner
// persists checksums even when a later step fails, so the migration
// lands once and never re-fires.
package cli

import (
	"fmt"
	"os"
	"sort"

	"github.com/reliant-labs/forge/internal/checksums"
	"github.com/reliant-labs/forge/internal/generator"
)

// tier2MigratedPaths is a single-load cache of the Tier-2 managed path
// set (constant for the binary's lifetime — derived from compiled-in
// template registries). Tests that need a synthetic set can reassign it.
var tier2MigratedPaths = generator.Tier2ManagedPaths()

// stepMigrateTemplateTiers flips stale Tier-1/legacy checksum entries to
// Tier-2 for paths whose template has been reclassified as scaffold-once,
// then converts any LEGACY fork-era entries (`forked: true`) to the
// disowned state. Never fails the pipeline: both migrations are
// metadata-only.
func stepMigrateTemplateTiers(ctx *pipelineContext) error {
	migrated := migrateTemplateTiers(ctx.Checksums, tier2MigratedPaths)
	if len(migrated) > 0 {
		fmt.Printf("📜 Migrated %d checksum entr%s to Tier-2 (template reclassified scaffold-once; file is user-owned now):\n",
			len(migrated), pluralYIes(len(migrated)))
		for _, m := range migrated {
			fmt.Printf("  ✓ %s%s\n", m.path, map[bool]string{true: " (legacy fork flag cleared — starter files aren't forks)", false: ""}[m.wasForked])
			// A previously-forked entry may have side renders parked under
			// .forge/render*; they were fork-reconcile state and are
			// meaningless for a user-owned Tier-2 file.
			if m.wasForked {
				if err := checksums.CleanSideRenders(ctx.AbsPath, m.path); err != nil {
					fmt.Fprintf(os.Stderr, "  warning: could not clean side renders for %s: %v\n", m.path, err)
				}
			}
		}
	}

	// Legacy fork → disowned conversion. The fork concept is gone: a
	// `forked: true` entry recorded by an older forge becomes a disowned
	// Tier-2 entry (user-owned, marker preserved for audit). Both fleets
	// audited to zero forks before this shipped, so this is
	// belt-and-braces for stragglers. Side renders are deliberately NOT
	// cleaned here — `forge unfork --merge` (the one-release migration
	// aid) may still need them to reconcile a legacy fork.
	converted := migrateLegacyForks(ctx.Checksums)
	if len(converted) > 0 {
		fmt.Printf("📜 Converted %d legacy forked entr%s to disowned (the fork state was removed; files are user-owned now):\n",
			len(converted), pluralYIes(len(converted)))
		for _, p := range converted {
			fmt.Printf("  ✓ %s\n", p)
		}
		fmt.Printf("   Forge never regenerates disowned files. To return one to forge ownership: delete it and run `forge generate`.\n")
		fmt.Printf("   To reconcile a legacy fork with the current template first: `forge unfork --merge <path>` (available this release only).\n")
	}
	return nil
}

// migrateLegacyForks converts every `forked: true` entry to the
// disowned shape (tier=2 + disowned marker) in place and returns the
// sorted list of converted paths. DisownedAt inherits the legacy
// ForkedAt timestamp when present so "how long has this been outside
// forge ownership" stays truthful across the migration.
func migrateLegacyForks(cs *generator.FileChecksums) []string {
	if cs == nil || len(cs.Files) == 0 {
		return nil
	}
	var converted []string
	for path, entry := range cs.Files {
		if !entry.Forked {
			continue
		}
		entry.Tier = 2
		entry.Disowned = true
		if entry.DisownedAt == "" {
			entry.DisownedAt = entry.ForkedAt
		}
		entry.Forked = false
		entry.Accepted = false
		entry.ForkedAt = ""
		cs.Files[path] = entry
		converted = append(converted, path)
	}
	sort.Strings(converted)
	return converted
}

// tierMigration records one entry flipped by migrateTemplateTiers.
type tierMigration struct {
	path      string
	wasForked bool
}

// migrateTemplateTiers applies the Tier-1→Tier-2 flip on cs in place and
// returns the migrated paths (sorted). Pure on everything except cs —
// split from the step so tests can drive it with synthetic manifests.
//
// Rules:
//   - Only paths present in tier2Paths are considered.
//   - Entries already tier=2 are left alone ENTIRELY — including their
//     forked flag. A tier=2 fork records a deliberate scaffold-ownership
//     transfer (audit already excludes those from the fork report);
//     erasing it would destroy user intent, not stale metadata.
//   - tier=1 and the legacy tier=0 both migrate: pre-tier checksums
//     covered exclusively Tier-1 emitters, so 0 is Tier-1-equivalent
//     (same back-compat posture as the stomp guard).
//   - Forked and Accepted are cleared on migrated entries: fork is a
//     Tier-1 concept ("forge stops regenerating this"), and a Tier-2
//     file is never regenerated to begin with.
func migrateTemplateTiers(cs *generator.FileChecksums, tier2Paths map[string]bool) []tierMigration {
	if cs == nil || len(cs.Files) == 0 {
		return nil
	}
	var migrated []tierMigration
	for path, entry := range cs.Files {
		if !tier2Paths[path] {
			continue
		}
		if entry.Tier == 2 {
			continue
		}
		migrated = append(migrated, tierMigration{path: path, wasForked: entry.Forked})
		entry.Tier = 2
		entry.Forked = false
		entry.Accepted = false
		cs.Files[path] = entry
	}
	sort.Slice(migrated, func(i, j int) bool { return migrated[i].path < migrated[j].path })
	return migrated
}

// pluralYIes returns "y" for n==1 and "ies" otherwise — for
// "entry"/"entries" style messages.
func pluralYIes(n int) string {
	if n == 1 {
		return "y"
	}
	return "ies"
}
